// // This module is designed to hold the current value of the input data 'd' when the 'load' signal is high, and to load a new value from 'd' on the negative edge of the 'clk' signal.
module register (
    input clk,
    input rst,
    input load,
    input [15:0] d,
    output reg [15:0] q
);

    always @(posedge clk) begin
        if (rst) begin
            q <= 16'd0;
        end else if (load) begin
            q <= d;
        end
    end

endmodule
